function solve(n, k) {
    if (k === 0) {
        return n >= 1 ? 1 : 0;
    }

    // Precompute the depth for numbers up to 60 bits
    const maxBits = 60;
    const depth = new Array(maxBits + 2).fill(0);
    depth[1] = 0;
    for (let i = 2; i <= maxBits; i++) {
        const nextNum = i.toString(2).split('1').length - 1;
        depth[i] = depth[nextNum] + 1;
    }

    // Find all target popcounts where depth[c] == k - 1
    const targetCList = [];
    for (let c = 1; c <= maxBits; c++) {
        if (depth[c] === k - 1) {
            targetCList.push(c);
        }
    }

    const s = n.toString(2);
    const m = s.length;
    let result = 0;

    for (const c of targetCList) {
        // Digit DP to count numbers with popcount == c
        const memo = new Map();
        function countNumbers(pos, cnt, tight) {
            const key = `${pos},${cnt},${tight}`;
            if (memo.has(key)) {
                return memo.get(key);
            }
            if (pos === m) {
                return cnt === c ? 1 : 0;
            }
            const limit = tight ? parseInt(s[pos], 10) : 1;
            let res = 0;
            for (let d = 0; d <= limit; d++) {
                const newTight = tight && (d === limit);
                const newCnt = cnt + (d === 1 ? 1 : 0);
                if (newCnt > c) {
                    continue;
                }
                res += countNumbers(pos + 1, newCnt, newTight);
            }
            memo.set(key, res);
            return res;
        }
        result += countNumbers(0, 0, true);
    }

    return result;
}
